import React, { useState, useEffect } from 'react';
import { dishAPI, restaurantAPI } from '../services/api';

const CustomerDashboard = ({ user, onLogout }) => {
  const [dishes, setDishes] = useState([]);
  const [restaurants, setRestaurants] = useState([]);
  const [selectedRestaurant, setSelectedRestaurant] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filteredDishes, setFilteredDishes] = useState([]);

  useEffect(() => {
    loadRestaurants();
  }, []);

  useEffect(() => {
    if (searchTerm) {
      searchDishes();
    } else {
      setFilteredDishes(dishes);
    }
  }, [searchTerm, dishes]);



  const loadRestaurants = async () => {
    try {
      const response = await restaurantAPI.getAll();
      setRestaurants(response.data);
    } catch (error) {
      console.error('Error loading restaurants:', error);
    }
  };

  const searchDishes = async () => {
    try {
      const response = await dishAPI.search(searchTerm);
      setFilteredDishes(response.data);
    } catch (error) {
      console.error('Error searching dishes:', error);
    }
  };

  const getRestaurantName = (restaurantId) => {
    const restaurant = restaurants.find(r => r.restaurantId === restaurantId);
    return restaurant ? restaurant.name : 'Unknown Restaurant';
  };

  const handleRestaurantClick = async (restaurant) => {
    setSelectedRestaurant(restaurant);
    try {
      const response = await dishAPI.getByRestaurant(restaurant.restaurantId);
      setDishes(response.data);
      setFilteredDishes(response.data);
    } catch (error) {
      console.error('Error loading restaurant dishes:', error);
    }
  };

  const handleBackToRestaurants = () => {
    setSelectedRestaurant(null);
    setDishes([]);
    setFilteredDishes([]);
    setSearchTerm('');
  };

  return (
    <div className="min-h-screen bg-gray-100">
      <nav className="bg-blue-600 text-white p-4">
        <div className="container mx-auto flex justify-between items-center">
          <h1 className="text-xl font-bold">SnackSmart - Customer Dashboard</h1>
          <div className="flex items-center space-x-4">
            <span>Welcome, {user.username}!</span>
            <button
              onClick={onLogout}
              className="bg-red-500 px-4 py-2 rounded hover:bg-red-600"
            >
              Logout
            </button>
          </div>
        </div>
      </nav>

      <div className="container mx-auto p-6">
        {!selectedRestaurant ? (
          // Restaurant List View
          <>
            <h2 className="text-2xl font-bold mb-6">Choose a Restaurant</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {restaurants.map((restaurant) => (
                <div 
                  key={restaurant.restaurantId} 
                  className="bg-white rounded-lg shadow-md p-6 cursor-pointer hover:shadow-lg transition-shadow"
                  onClick={() => handleRestaurantClick(restaurant)}
                >
                  <h3 className="text-xl font-semibold mb-2">{restaurant.name}</h3>
                  <p className="text-gray-600 mb-4">{restaurant.location}</p>
                  <p className="text-sm text-blue-600">Click to view menu →</p>
                </div>
              ))}
            </div>
            {restaurants.length === 0 && (
              <div className="text-center py-8">
                <p className="text-gray-500">No restaurants available.</p>
              </div>
            )}
          </>
        ) : (
          // Restaurant Menu View
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <button
                  onClick={handleBackToRestaurants}
                  className="text-blue-600 hover:text-blue-800 mb-2"
                >
                  ← Back to Restaurants
                </button>
                <h2 className="text-2xl font-bold">{selectedRestaurant.name} Menu</h2>
                <p className="text-gray-600">{selectedRestaurant.location}</p>
              </div>
              <input
                type="text"
                placeholder="Search dishes..."
                className="max-w-md px-4 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredDishes.map((dish) => (
                <div key={dish.dishId} className="bg-white rounded-lg shadow-md p-6">
                  {dish.imageUrl && (
                    <img
                      src={dish.imageUrl}
                      alt={dish.name}
                      className="w-full h-48 object-cover rounded-lg mb-4"
                    />
                  )}
                  <h3 className="text-xl font-semibold mb-2">{dish.name}</h3>
                  <p className="text-gray-600 mb-2">{dish.description}</p>
                  <p className="text-sm text-gray-500 mb-2">Category: {dish.category}</p>
                  <p className="text-2xl font-bold text-green-600">${dish.price}</p>
                </div>
              ))}
            </div>

            {filteredDishes.length === 0 && (
              <div className="text-center py-8">
                <p className="text-gray-500">No dishes found in this restaurant.</p>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
};

export default CustomerDashboard;
